using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        // Dispatchers: get all shipments
        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (
            ApplicationDbContext db,
            string? status,
            string? search) =>
        {
            var query = db.Shipments.AsQueryable();

            if (!string.IsNullOrWhiteSpace(status) &&
                Enum.TryParse<Data.ShipmentStatus>(status, true, out var s))
            {
                query = query.Where(x => x.Status == s);
            }

            if (!string.IsNullOrWhiteSpace(search))
            {
                query = query.Where(x =>
                    x.TrackingNumber.Contains(search) ||
                    x.Destination.Contains(search) ||
                    x.RecipientName.Contains(search));
            }

            var shipments = await query
                .OrderByDescending(x => x.CreatedAt)
                .Select(x => ToDto(x))
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // Dispatchers: update shipment status
        group.MapPut("/{id:int}/status", [Authorize(Roles = "Dispatcher")] async (
            int id,
            UpdateShipmentStatusRequest request,
            ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = (Data.ShipmentStatus)(int)request.Status;

            if (request.Status == Client.Models.ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(ToDto(shipment));
        });

        // Dispatchers: create a new shipment
        group.MapPost("/", [Authorize(Roles = "Dispatcher")] async (
            ShipmentDto dto,
            ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = Data.ShipmentStatus.Pending,
                CreatedAt = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                RecipientName = dto.RecipientName,
                Description = dto.Description,
                WeightKg = dto.WeightKg
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", ToDto(shipment));
        });

        // Public: track a shipment by tracking number
        group.MapGet("/track/{trackingNumber}", async (
            string trackingNumber,
            ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(x => x.TrackingNumber == trackingNumber);

            return shipment is null
                ? Results.NotFound(new { message = "Shipment not found" })
                : Results.Ok(ToDto(shipment));
        });
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (Client.Models.ShipmentStatus)(int)s.Status,
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description,
        WeightKg = s.WeightKg
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
    }
}

