using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync(string? status = null, string? search = null)
    {
        var url = "/api/shipments?";
        if (!string.IsNullOrWhiteSpace(status))
            url += $"status={Uri.EscapeDataString(status)}&";
        if (!string.IsNullOrWhiteSpace(search))
            url += $"search={Uri.EscapeDataString(search)}&";

        return await http.GetFromJsonAsync<List<ShipmentDto>>(url.TrimEnd('&', '?')) ?? [];
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode)
            return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var response = await http.PutAsJsonAsync(
            $"/api/shipments/{id}/status",
