@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject ShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>📦 Dispatcher Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Search by tracking #, destination, or recipient..."
               @bind="searchTerm" @bind:event="oninput" @onkeyup="HandleSearch" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-primary" @onclick="() => showCreateForm = !showCreateForm">
            @(showCreateForm ? "Cancel" : "➕ New Shipment")
        </button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5 class="card-title">Create New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Recipient" @bind="newShipment.RecipientName" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Description" @bind="newShipment.Description" />
                </div>
                <div class="col-md-2">
                    <input type="number" step="0.1" class="form-control" placeholder="Weight (kg)" @bind="newShipment.WeightKg" />
                </div>
                <div class="col-md-3">
                    <label class="form-label small">Estimated Delivery</label>
                    <input type="date" class="form-control" @bind="estimatedDeliveryDate" />
                </div>
                <div class="col-md-2">
                    <button class="btn btn-success" @onclick="CreateShipment">Create</button>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(createMessage))
            {
                <div class="alert alert-info mt-2">@createMessage</div>
            }
        </div>
    </div>
}

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is null || shipments.Count == 0)
{
    <p class="text-muted">No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Weight</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td>@shipment.WeightKg kg</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@s" selected="@(s == shipment.Status)">@s</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private bool loading = true;
    private string searchTerm = "";
    private string statusFilter = "";
    private bool showCreateForm;
    private ShipmentDto newShipment = new();
    private DateTime? estimatedDeliveryDate;
    private string? createMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync(
            string.IsNullOrEmpty(statusFilter) ? null : statusFilter,
            string.IsNullOrEmpty(searchTerm) ? null : searchTerm);
        loading = false;
    }

    private async Task HandleSearch()
    {
        await LoadShipments();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
                shipment.ActualDelivery = updated.ActualDelivery;
            }
        }
    }

    private async Task CreateShipment()
    {
        newShipment.EstimatedDelivery = estimatedDeliveryDate;
        var created = await ShipmentService.CreateShipmentAsync(newShipment);
        if (created is not null)
        {
            createMessage = $"Created shipment {created.TrackingNumber}";
            newShipment = new();
            estimatedDeliveryDate = null;
            await LoadShipments();
        }
        else
        {
            createMessage = "Failed to create shipment.";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
