@rendermode InteractiveAuto
@inject ShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control form-control-lg" placeholder="Enter tracking number (e.g. SHP-20260101-1001)"
                   @bind="trackingNumber" @onkeyup="HandleKeyPress" />
            <button class="btn btn-primary btn-lg" @onclick="TrackShipment" disabled="@searching">
                @(searching ? "Searching..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (notFound)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>.
        Please check the number and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card shadow-sm">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h4 class="mb-0">
                <code>@shipment.TrackingNumber</code>
            </h4>
            <span class="badge fs-6 @GetStatusBadgeClass(shipment.Status)">
                @GetStatusEmoji(shipment.Status) @shipment.Status
            </span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>From</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>To</dt>
                        <dd>@shipment.Destination</dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>

                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>

                        <dt>Weight</dt>
                        <dd>@shipment.WeightKg kg</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped On</dt>
                        <dd>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                <span class="fw-bold text-primary">
                                    @shipment.EstimatedDelivery.Value.ToString("MMMM dd, yyyy")
                                </span>
                                @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                {
                                    var daysLeft = (shipment.EstimatedDelivery.Value.Date - DateTime.UtcNow.Date).Days;
                                    <br />
                                    <small class="text-muted">
                                        @if (daysLeft > 0)
                                        {
                                            @($"({daysLeft} day{(daysLeft == 1 ? "" : "s")} remaining)")
                                        }
                                        else if (daysLeft == 0)
                                        {
                                            @("(Expected today)")
                                        }
                                        else
                                        {
                                            @($"({Math.Abs(daysLeft)} day{(Math.Abs(daysLeft) == 1 ? "" : "s")} overdue)")
                                        }
                                    </small>
                                }
                            }
                            else
                            {
                                <span class="text-muted">Not yet estimated</span>
                            }
                        </dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Delivered On</dt>
                            <dd class="text-success fw-bold">
                                @shipment.ActualDelivery.Value.ToString("MMMM dd, yyyy 'at' HH:mm UTC")
                            </dd>
                        }
                    </dl>
                </div>
            </div>

            <!-- Progress tracker -->
            <h5 class="mt-3">Shipment Progress</h5>
            <div class="d-flex justify-content-between position-relative mt-2 mb-4 px-2">
                @{
                    var stages = new[] {
                        ShipmentStatus.Pending,
                        ShipmentStatus.PickedUp,
                        ShipmentStatus.InTransit,
                        ShipmentStatus.OutForDelivery,
                        ShipmentStatus.Delivered
                    };
                    var currentIndex = shipment.Status == ShipmentStatus.Cancelled
                        ? -1
                        : Array.IndexOf(stages, shipment.Status);
                }
                @for (int i = 0; i < stages.Length; i++)
                {
                    var isActive = i <= currentIndex;
                    <div class="text-center" style="flex: 1;">
                        <div class="rounded-circle d-inline-flex align-items-center justify-content-center @(isActive ? "bg-success text-white" : "bg-light text-muted border")"
                             style="width: 40px; height: 40px;">
                            @(isActive ? "✓" : (i + 1).ToString())
                        </div>
                        <div class="small mt-1">@stages[i]</div>
                    </div>
                }
            </div>

            @if (shipment.Status == ShipmentStatus.Cancelled)
            {
                <div class="alert alert-danger">This shipment has been cancelled.</div>
            }
        </div>
    </div>
}

