@code {
    private string trackingNumber = "";
    private string? searchedNumber;
    private ShipmentDto? shipment;
    private bool notFound;
    private bool searching;

    private async Task HandleKeyPress(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        searching = true;
        notFound = false;
        shipment = null;
        searchedNumber = trackingNumber.Trim();

        shipment = await ShipmentService.TrackShipmentAsync(searchedNumber);
        notFound = shipment is null;
        searching = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetStatusEmoji(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "⏳",
        ShipmentStatus.PickedUp => "📥",
        ShipmentStatus.InTransit => "🚚",
        ShipmentStatus.OutForDelivery => "🏃",
        ShipmentStatus.Delivered => "✅",
        ShipmentStatus.Cancelled => "❌",
        _ => "📦"
    };
}

